+		fmt.Fprintf(os.Stderr, "  Imported %d issues", result.IssuesImported)
+		if result.IssuesSkipped > 0 {
+			fmt.Fprintf(os.Stderr, ", skipped %d duplicates", result.IssuesSkipped)
+		}
